import { ComponentModule } from '@/main';
import { DRAWER_TOGGLE } from '@/models/events';
import { getAuthenticatedCompany } from '@/services/auth.service';
import { getMenuItems } from '@/services/menu.service';
import { Drawer } from 'flowbite';

const breakPoint = 1024;

export default {
    name: () => 'aside',
    template: () => import('./aside.html?raw'),
    data: () => ({
        loading: false,
        empresa: getAuthenticatedCompany(),
        drawer: null as Drawer | null,
        menu: getMenuItems(),
        async init() {
            console.log('aside@init');

            // TODO: use this.empresa to control menu items to display

            this.drawer = new Drawer(this.$refs.drawerNavigation, {
                placement: 'left',
                backdrop: false,
                // backdropClasses: 'bg-gray-900/50 dark:bg-gray-900/80 fixed inset-0 z-30',
                bodyScrolling: true,
                edge: false,
                edgeOffset: '',
                onHide: () => {
                    console.log('drawer is hidden');
                },
                onShow: () => {
                    console.log('drawer is shown');
                },
                onToggle: () => {
                    console.log('drawer has been toggled');
                },
            });

            this.$nextTick(() => {
                if (window.innerWidth >= breakPoint) {
                    this.drawer?.show();
                }

                console.log('aside drawer visible status', this.drawer?.isVisible());

                window.onresize = () => {
                    if (window.innerWidth >= breakPoint) {
                        this.drawer?.show();
                    }

                    if (window.innerWidth < breakPoint) {
                        this.drawer?.hide();
                    }
                };

                // @ts-expect-error 2769
                window.addEventListener(DRAWER_TOGGLE, (e: CustomEvent) => {
                    if (e.detail === 'drawerNavigation') {
                        this.drawer?.toggle();
                    }
                });
            });
        },
    }),
} as ComponentModule;
